USE master;
GO
IF EXISTS (SELECT name FROM sys.databases WHERE name = 'LogisticaUltimaMilla') DROP DATABASE LogisticaUltimaMilla;
GO
CREATE DATABASE LogisticaUltimaMilla;
GO
USE LogisticaUltimaMilla;
GO

CREATE TABLE Geografia (
    ID_Geografia INT PRIMARY KEY IDENTITY(1,1),
    Departamento NVARCHAR(50),
    Ciudad NVARCHAR(50)
);

CREATE TABLE Vehiculos (
    ID_Vehiculo INT PRIMARY KEY IDENTITY(1,1),
    Modelo NVARCHAR(100),
    Tipo NVARCHAR(50),
    Capacidad_KG DECIMAL(10,2)
);

CREATE TABLE Conductores (
    ID_Conductor INT PRIMARY KEY IDENTITY(1,1),
    Nombre NVARCHAR(100),
    Licencia NVARCHAR(20),
    Telefono NVARCHAR(20)
);

CREATE TABLE Clientes (
    ID_Cliente INT PRIMARY KEY IDENTITY(1,1),
    Nombre_Empresa NVARCHAR(100),
    Contacto NVARCHAR(100),
    ID_Geografia INT FOREIGN KEY REFERENCES Geografia(ID_Geografia)
);

CREATE TABLE Entregas_Bronze (
    ID_Entrega INT PRIMARY KEY IDENTITY(1,1),
    Fecha_Hora DATETIME,
    ID_Vehiculo INT FOREIGN KEY REFERENCES Vehiculos(ID_Vehiculo),
    ID_Conductor INT FOREIGN KEY REFERENCES Conductores(ID_Conductor),
    ID_Cliente INT FOREIGN KEY REFERENCES Clientes(ID_Cliente),
    ID_Origen INT FOREIGN KEY REFERENCES Geografia(ID_Geografia),
    ID_Destino INT FOREIGN KEY REFERENCES Geografia(ID_Geografia),
    Distancia_KM DECIMAL(10,2),
    Consumo_Combustible_Litros DECIMAL(10,2),
    Peso_Carga_KG DECIMAL(10,2),
    Tiempo_Idling_Minutos INT,
    Emisiones_CO2_KG DECIMAL(10,2),
    Estado_Entrega NVARCHAR(50)
);
GO

PRINT 'Insertando 5000 registros en Entregas_Bronze...';
SET NOCOUNT ON;
